import{_ as e,o as a,c as n,ag as t}from"./chunks/framework.eQLvDOR_.js";const u=JSON.parse(`{"title":"Google engineer automated 80% of his work with Claude Code. here's the exact system he built.","description":"","frontmatter":{"title":"Google engineer automated 80% of his work with Claude Code. here's the exact system he built.","source":"https://x.com/noisyb0y1/article/2043609541477044439","clipped_at":"2026-04-18","category":"Claude_Code_Skills","tags":["claude-code","karpathy-rules","agent-system"],"status":"distilled","compiled":true},"headers":[],"relativePath":"library/Claude_Code_Skills/Claude_Code_Skills - Google engineer automated 80percent of his work with Claude Code. here's the exact system he built..md","filePath":"library/Claude_Code_Skills/Claude_Code_Skills - Google engineer automated 80percent of his work with Claude Code. here's the exact system he built..md","lastUpdated":null}`),i={name:"library/Claude_Code_Skills/Claude_Code_Skills - Google engineer automated 80percent of his work with Claude Code. here's the exact system he built..md"};function p(l,s,o,r,d,h){return a(),n("div",null,[...s[0]||(s[0]=[t(`<p><img src="https://pbs.twimg.com/media/HFxJCx7XoAAcjrL?format=jpg&amp;name=large" alt="Image"></p><p>Google engineer with 11 years of experience automated 80% of his work using Claude Code and a simple dotnet app. Now he works 2-3 hours a day instead of 8 and chills the rest of the time while the system runs itself making $28,000 in passive income.</p><p>Here&#39;s what he knows that you don&#39;t.</p><h2 id="part-1-claude-md-by-karpathy-s-rules" tabindex="-1">Part 1 - CLAUDE.md by Karpathy&#39;s rules <a class="header-anchor" href="#part-1-claude-md-by-karpathy-s-rules" aria-label="Permalink to &quot;Part 1 - CLAUDE.md by Karpathy&#39;s rules&quot;">​</a></h2><p>Andrej Karpathy - one of the most influential AI researchers in the world - documented the most common mistakes LLMs make when writing code: over-engineering, ignoring existing patterns, adding dependencies nobody asked for.</p><p><img src="https://pbs.twimg.com/media/HFxKUIIXsAA5TLf?format=jpg&amp;name=large" alt="Image"></p><p>Someone took these observations and turned them into a single CLAUDE.md file. The result - 15,000 stars on GitHub in a week, you could say 15k people changed their lives</p><p>The idea is simple: if mistakes are predictable — they can be prevented with the right instructions. One markdown file in the repo gives Claude Code a structured set of behavioral rules for the entire project.</p><p><strong>Four principles inside:</strong></p><div class="language-plaintext vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plaintext</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Think Before Coding    → stops wrong assumptions and missed tradeoffs</span></span>
<span class="line"><span>Simplicity First       → stops over-engineering and bloated abstractions</span></span>
<span class="line"><span>Surgical Changes       → stops touching code nobody asked to touch</span></span>
<span class="line"><span>Goal-Driven Execution  → tests first, verified success criteria</span></span></code></pre></div><p>No frameworks. No complex tooling. One file that changes Claude&#39;s behavior at the project level.</p><p><strong>Real difference:</strong></p><div class="language-plaintext vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plaintext</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Without CLAUDE.md:           Claude breaks conventions in ~40% of cases</span></span>
<span class="line"><span>With Karpathy CLAUDE.md:     violations drop to ~3%</span></span>
<span class="line"><span>Setup time:                  5 minutes</span></span></code></pre></div><p>Command that auto-generates your own CLAUDE.md:</p><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">claude </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">p </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Read the entire project and create a CLAUDE.md based on:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Think Before Coding, Simplicity First, Surgical Changes, Goal</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Driven Execution.</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Adapt to the real architecture you see.</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot; --allowedTools Bash,Write,Read</span></span></code></pre></div><p><strong>Replaces:</strong> Claude that over-engineers simple tasks, adds dependencies nobody asked for and touches files it shouldn&#39;t.</p><h2 id="part-2-everything-claude-code-a-full-engineering-team-in-one-repo" tabindex="-1">Part 2 - Everything Claude Code: a full engineering team in one repo <a class="header-anchor" href="#part-2-everything-claude-code-a-full-engineering-team-in-one-repo" aria-label="Permalink to &quot;Part 2 - Everything Claude Code: a full engineering team in one repo&quot;">​</a></h2><blockquote><p><a href="https://github.com/affaan-m/everything-claude-code" target="_blank" rel="noreferrer">github.com/affaan-m/everything-claude-code</a> ( 153,000+ stars )</p></blockquote><p>This isn&#39;t just a prompt collection. It&#39;s a complete AI operating system for building products.</p><p><img src="https://pbs.twimg.com/media/HFxK4FCWAAAGRGo?format=jpg&amp;name=large" alt="Image"></p><div class="language-plaintext vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plaintext</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>30+ specialized agents:</span></span>
<span class="line"><span>planner.md           → feature planning</span></span>
<span class="line"><span>architect.md         → system decisions</span></span>
<span class="line"><span>tdd-guide.md         → test-driven development</span></span>
<span class="line"><span>code-reviewer.md     → quality and security review</span></span>
<span class="line"><span>security-reviewer.md → vulnerability analysis</span></span>
<span class="line"><span>loop-operator.md     → autonomous loop execution</span></span></code></pre></div><div class="language-plaintext vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plaintext</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>180+ skills:</span></span>
<span class="line"><span>TDD, security, research, content — all already written</span></span></code></pre></div><div class="language-plaintext vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plaintext</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>AgentShield built in:</span></span>
<span class="line"><span>1,282 security tests right in the config</span></span>
<span class="line"><span>productivity AND protection at the same time</span></span></code></pre></div><p>Works on Claude, Codex, Cursor, OpenCode, Gemini - one system everywhere.</p><p><strong>How to install:</strong></p><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">plugin marketplace add affaan</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">m</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">everything</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">claude</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">code</span></span></code></pre></div><p>Or manually - copy the components you need into your project&#39;s .claude/. Don&#39;t load everything at once - 27 agents and 64 skills in context simultaneously will burn your limits faster than you can type your first prompt. Take only what you actually need.</p><p><strong>Real difference:</strong></p><div class="language-plaintext vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plaintext</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Before:  you chat with AI</span></span>
<span class="line"><span>After:   you manage a team of AI engineers on autopilot</span></span></code></pre></div><p>Replaces: weeks of setting up your own agent system, separate tools for planning/review/security, $200-500/month on specialized AI services.</p><h2 id="part-3-the-hidden-scandal-claude-code-v2-1-100-is-silently-stealing-your-tokens" tabindex="-1">Part 3 - The hidden scandal: Claude Code v2.1.100 is silently stealing your tokens <a class="header-anchor" href="#part-3-the-hidden-scandal-claude-code-v2-1-100-is-silently-stealing-your-tokens" aria-label="Permalink to &quot;Part 3 - The hidden scandal: Claude Code v2.1.100 is silently stealing your tokens&quot;">​</a></h2><p>Someone set up an HTTP proxy to intercept full API requests across 4 different Claude Code versions. <strong>Here&#39;s what they found:</strong></p><div class="language-plaintext vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plaintext</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>v2.1.98:   169,514 bytes request → 49,726 tokens charged</span></span>
<span class="line"><span>v2.1.100:  168,536 bytes request → 69,922 tokens charged</span></span>
<span class="line"><span>difference: -978 bytes but +20,196 tokens</span></span></code></pre></div><p>v2.1.100 sends FEWER bytes but charges 20,000 MORE tokens. The inflation is entirely server-side - you can&#39;t see it and can&#39;t verify it through /context.</p><p><img src="https://pbs.twimg.com/media/HFxKdmQXEAA787e?format=jpg&amp;name=large" alt="Image"></p><p><strong>Why this matters beyond billing:</strong></p><div class="language-plaintext vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plaintext</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Those 20,000 tokens go into Claude&#39;s actual context window.</span></span>
<span class="line"><span>Which means:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>→ your CLAUDE.md instructions get diluted by 20K tokens of hidden content</span></span>
<span class="line"><span>→ quality degrades faster in long sessions</span></span>
<span class="line"><span>→ when Claude ignores your rules — you can&#39;t figure out why</span></span>
<span class="line"><span>→ Claude Max limits burn 40% faster than they should</span></span></code></pre></div><p><strong>Fix takes 30 seconds:</strong></p><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">npx claude</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">code</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">@</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2.1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.98</span></span></code></pre></div><p>Temporary solution until Anthropic officially fixes the issue. But the difference in sessions is noticeable immediately.</p><p><strong>Replaces:</strong> guessing why Claude suddenly stopped following your instructions.</p><p><strong>Case study: what full automation looks like</strong></p><p>An engineer with 11 years of experience built a three-part system:</p><div class="language-plaintext vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plaintext</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>STEP 1 — Classification:</span></span>
<span class="line"><span>dotnet app calls GitLab API every 15 minutes</span></span>
<span class="line"><span>→ Claude reads the issue and decides if it&#39;s ready for development</span></span>
<span class="line"><span>→ if not — posts a draft response on GitLab for review</span></span>
<span class="line"><span></span></span>
<span class="line"><span>STEP 2 — Execution:</span></span>
<span class="line"><span>if issue is ready → subagent starts working</span></span>
<span class="line"><span>→ pushes to a new branch</span></span>
<span class="line"><span>→ creates PR for review</span></span>
<span class="line"><span></span></span>
<span class="line"><span>STEP 3 — PR workflow:</span></span>
<span class="line"><span>→ checks if there&#39;s a PR for the issue</span></span>
<span class="line"><span>→ checks for new comments</span></span>
<span class="line"><span>→ implements comments from PR</span></span></code></pre></div><p><strong>Result after a week:</strong></p><div class="language-plaintext vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plaintext</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Before:  8 hours of coding per day</span></span>
<span class="line"><span>After:   2-3 hours of review and testing</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Code quality:    the same — he reviews everything</span></span>
<span class="line"><span>Status in Teams: online — mouse moves every minute automatically</span></span>
<span class="line"><span>Rest of the day: free</span></span></code></pre></div><p>This isn&#39;t magic. It&#39;s CLAUDE.md + the right agents + a 15-minute cycle.</p><p><strong>Full checklist</strong></p><div class="language-plaintext vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plaintext</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>STEP 1 — Karpathy CLAUDE.md (5 minutes):</span></span>
<span class="line"><span>claude -p &quot;Create a CLAUDE.md based on Karpathy&#39;s principles for this project&quot;</span></span>
<span class="line"><span>--allowedTools Bash,Write,Read</span></span>
<span class="line"><span></span></span>
<span class="line"><span>STEP 2 — Everything Claude Code (10 minutes):</span></span>
<span class="line"><span>/plugin marketplace add affaan-m/everything-claude-code</span></span>
<span class="line"><span>Install only the agents you need — not all at once</span></span>
<span class="line"><span></span></span>
<span class="line"><span>STEP 3 — Token fix (30 seconds):</span></span>
<span class="line"><span>npx claude-code@2.1.98</span></span></code></pre></div><p><strong>What you get after reading this</strong></p><div class="language-plaintext vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plaintext</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Before:  Claude breaks conventions in 40% of cases</span></span>
<span class="line"><span>After:   violations drop to 3% with Karpathy CLAUDE.md</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Before:  you spend weeks setting up agents</span></span>
<span class="line"><span>After:   27 agents ready to work out of the box</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Before:  Claude Max burns out in 2-3 hours</span></span>
<span class="line"><span>After:   downgrade to v2.1.98 gives 40% of limits back</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Before:  8 hours of coding per day</span></span>
<span class="line"><span>After:   2-3 hours of review while the system runs itself</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Setup time:         15-20 minutes</span></span>
<span class="line"><span>Saved per day:      5-6 hours</span></span>
<span class="line"><span>Saved per month:    100-120 hours</span></span></code></pre></div><p>&gt; If your time is worth $30/hr - that&#39;s $3,000-3,600/month you&#39;re just not seeing right now. &gt; If $100/hr - that&#39;s $10,000-12,000/month going nowhere while you manually write code Claude could write itself.</p><p>Most developers will never reach this level - not because they can&#39;t, but because they think it&#39;s complicated. In reality between you and full automation there are three commands and one file.</p><p>The engineer I described at the beginning isn&#39;t a genius or a senior from Google. He just spent one evening on the right setup and now his system does the work while he lives his life.</p><p>You can do the same thing tonight. While others argue about whether AI will replace developers - those who already set up the system just collect their pay and chill.</p><p>The choice is obvious.</p><p><strong>You build your own life - so choose the right path. / If this was useful - follow /</strong></p>`,57)])])}const g=e(i,[["render",p]]);export{u as __pageData,g as default};
